example.code:
{
  "objective": "lead_generation",
  "audience": {
    "matched_accounts": "acme_top500",
    "icp_filters": {
      "seniority": [
        "director",
        "vp"
      ],
      "function": [
        "engineering"
      ],
      "company_size": "201-1000"
    },
    "exclusions": [
      "competitors_list",
      "current_customers"
    ]
  },
  "formats": [
    "single_image",
    "lead_form"
  ],
  "bid_strategy": "cost_cap",
  "budget": {
    "daily": 200,
    "currency": "USD"
  },
  "creative_brief": {
    "hook": "Ship 2 weeks faster",
    "value_prop": "Faion-CLI cuts SDD planning to minutes",
    "cta": "Get the playbook"
  },
  "kpi": {
    "target_cost_per_mql": 80,
    "target_mql_to_sql": 0.25
  }
}
